SELECT status, COUNT(*) AS task_count
FROM data_processing_tasks
GROUP BY status;

SELECT alert_id, description
FROM alerts
WHERE severity = 'medium';

SELECT AVG(r.cost) AS average_cost
FROM resource_allocations r
WHERE r.efficiency_rating < 50;

SELECT resource_type, AVG(cost) AS average_cost
FROM resource_allocations
GROUP BY resource_type;

SELECT title, generated_time, summary
FROM reports
ORDER BY generated_time DESC;

SELECT task_id, task_name
FROM data_processing_tasks
ORDER BY task_id;

SELECT permission_name, module, actions
FROM permissions
WHERE description = 'Read and write access to system data';

SELECT user_id, COUNT(*) AS report_count
FROM reports
GROUP BY user_id;

SELECT COUNT(*) AS report_count
FROM reports
WHERE user_id = 0;
